        self.cache = {}
        self.load_cache()

    def load_cache(self):
        if os.path.exists(self.index_file_path):
            with open(self.index_file_path, 'rb') as f:
                self.cache = pickle.load(f)

    def save_cache(self):
        with open(self.index_file_path, 'wb') as f:
            pickle.dump(self.cache, f)

    def add_item(self, key, value):
